  /the (?:deadline|requirement|condition|criteria) (?:is|are)/gi,
  /(?:federal|cantonal) (?:benefits?|support|assistance) (?:include|cover|provide)/gi,
  /(?:CHF|Fr\.)\s*[\d,.']+/gi,
